import{_ as s,o as e,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Node.js 环境（CLI 可选）","description":"","frontmatter":{},"headers":[],"relativePath":"guide/nodejs-git.md","filePath":"guide/nodejs-git.md","lastUpdated":1782205652000}'),n={name:"guide/nodejs-git.md"};function l(d,a,p,h,o,r){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="node-js-环境-cli-可选" tabindex="-1">Node.js 环境（CLI 可选） <a class="header-anchor" href="#node-js-环境-cli-可选" aria-label="Permalink to &quot;Node.js 环境（CLI 可选）&quot;">​</a></h1><p>本页属于 Codex安装章节，只给使用 Codex CLI 的用户作为补充说明。如果你安装的是 Codex App，通常不需要先安装 Node.js，可以直接继续完成 <a href="/guide/register">平台注册</a>、<a href="/guide/recharge">账号充值</a> 和 <a href="/guide/api-key">API Key</a>。</p><p>Codex CLI 本身可以通过官方脚本安装，不一定需要你提前准备 Node.js。只有在下面这些情况里，才建议看本页：</p><table tabindex="0"><thead><tr><th>场景</th><th>是否需要 Node.js</th></tr></thead><tbody><tr><td>使用 Codex App</td><td>不需要</td></tr><tr><td>使用官方脚本安装 Codex CLI</td><td>通常不需要提前安装</td></tr><tr><td>使用 <code>npm install -g @openai/codex</code> 安装 Codex CLI</td><td>需要</td></tr><tr><td>使用 <code>npm install -g @openai/codex@latest</code> 更新 Codex CLI</td><td>需要</td></tr><tr><td>后续需要在项目里运行 npm、pnpm、yarn 等前端命令</td><td>需要</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">关于 Git</p><p>Git 不是 Codex CLI 的必装前置。Codex CLI 可以在普通文件夹里启动。只有当你要处理 Git 仓库、查看提交历史、创建提交或推送代码时，再按需安装 Git 即可。</p></div><h2 id="安装前先确认" tabindex="-1">安装前先确认 <a class="header-anchor" href="#安装前先确认" aria-label="Permalink to &quot;安装前先确认&quot;">​</a></h2><p>先打开终端执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><p>如果两条命令都能看到版本号，说明 Node.js 和 npm 已经可用，可以跳过安装步骤。</p><p>如果提示 <code>command not found</code>、<code>不是内部或外部命令</code>，或者完全没有版本号，再按下面步骤安装。</p><h2 id="macos-安装" tabindex="-1">macOS 安装 <a class="header-anchor" href="#macos-安装" aria-label="Permalink to &quot;macOS 安装&quot;">​</a></h2><h3 id="方式一-使用官方安装包" tabindex="-1">方式一：使用官方安装包 <a class="header-anchor" href="#方式一-使用官方安装包" aria-label="Permalink to &quot;方式一：使用官方安装包&quot;">​</a></h3><p>普通用户推荐使用官方安装包：</p><ol><li>打开 <a href="https://nodejs.org/" target="_blank" rel="noreferrer">nodejs.org</a>。</li><li>下载 LTS 版本安装包。</li><li>双击安装包，按提示完成安装。</li><li>安装完成后，关闭当前终端窗口，再重新打开一个终端。</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>LTS 是长期维护版本，更适合日常使用。不要为了追新安装实验版本，除非你明确知道自己需要它。</p></div><h3 id="方式二-使用-homebrew" tabindex="-1">方式二：使用 Homebrew <a class="header-anchor" href="#方式二-使用-homebrew" aria-label="Permalink to &quot;方式二：使用 Homebrew&quot;">​</a></h3><p>如果你的电脑已经安装 Homebrew，也可以在终端执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span></span></code></pre></div><p>安装完成后，关闭当前终端窗口，再重新打开一个终端。</p><h2 id="windows-安装" tabindex="-1">Windows 安装 <a class="header-anchor" href="#windows-安装" aria-label="Permalink to &quot;Windows 安装&quot;">​</a></h2><h3 id="方式一-使用官方安装包-1" tabindex="-1">方式一：使用官方安装包 <a class="header-anchor" href="#方式一-使用官方安装包-1" aria-label="Permalink to &quot;方式一：使用官方安装包&quot;">​</a></h3><ol><li>打开 <a href="https://nodejs.org/" target="_blank" rel="noreferrer">nodejs.org</a>。</li><li>下载 LTS 版本安装包。</li><li>双击安装包，按默认选项安装。</li><li>安装完成后，重新打开 PowerShell、命令提示符或 Windows Terminal。</li></ol><h3 id="方式二-使用-winget" tabindex="-1">方式二：使用 winget <a class="header-anchor" href="#方式二-使用-winget" aria-label="Permalink to &quot;方式二：使用 winget&quot;">​</a></h3><p>如果你的系统支持 winget，可以在 PowerShell 中执行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">winget install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">id OpenJS.NodeJS.LTS </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span></span></code></pre></div><p>安装完成后，关闭当前终端窗口，再重新打开一个终端。</p><h2 id="验证安装结果" tabindex="-1">验证安装结果 <a class="header-anchor" href="#验证安装结果" aria-label="Permalink to &quot;验证安装结果&quot;">​</a></h2><p>重新打开终端后，执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><p>如果能看到版本号，说明 Node.js 和 npm 已经安装成功。</p><p>还可以检查命令路径：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-zDnFN" id="tab-DjtwH1f" checked><label data-title="macOS" for="tab-DjtwH1f">macOS</label><input type="radio" name="group-zDnFN" id="tab-bSWCFz3"><label data-title="Windows" for="tab-bSWCFz3">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> node</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> npm</span></span></code></pre></div></div></div><p>这些命令会显示工具安装在电脑上的具体位置。只要能显示路径，通常就说明系统已经能找到它们。</p><h2 id="用-npm-安装或更新-codex-cli" tabindex="-1">用 npm 安装或更新 Codex CLI <a class="header-anchor" href="#用-npm-安装或更新-codex-cli" aria-label="Permalink to &quot;用 npm 安装或更新 Codex CLI&quot;">​</a></h2><p>如果你选择 npm 方式安装 Codex CLI，可以执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @openai/codex</span></span></code></pre></div><p>如果你已经用 npm 安装过 Codex CLI，可以执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @openai/codex@latest</span></span></code></pre></div><p>安装或更新完成后，重新打开终端，执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>如果能看到版本号，说明 Codex CLI 已经可以使用。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="node-或-npm-命令找不到" tabindex="-1">node 或 npm 命令找不到 <a class="header-anchor" href="#node-或-npm-命令找不到" aria-label="Permalink to &quot;node 或 npm 命令找不到&quot;">​</a></h3><p>通常是安装后终端没有重新加载环境变量。先关闭所有终端窗口，再重新打开终端执行验证命令。</p><p>如果还是找不到：</p><ul><li>确认安装包已经完整安装成功。</li><li>Windows 用户重新打开 PowerShell、命令提示符或 Windows Terminal。</li><li>macOS 用户如果使用 Homebrew，确认 <code>brew doctor</code> 没有明显错误提示。</li></ul><h3 id="npm-安装-codex-cli-失败" tabindex="-1">npm 安装 Codex CLI 失败 <a class="header-anchor" href="#npm-安装-codex-cli-失败" aria-label="Permalink to &quot;npm 安装 Codex CLI 失败&quot;">​</a></h3><p>先确认：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><p>如果 Node.js 和 npm 都正常，但 npm 安装仍然失败，可以先改用 <a href="/guide/codex-install">Codex 下载安装</a> 里的官方脚本方式安装 Codex CLI。</p><h3 id="npm-下载速度慢" tabindex="-1">npm 下载速度慢 <a class="header-anchor" href="#npm-下载速度慢" aria-label="Permalink to &quot;npm 下载速度慢&quot;">​</a></h3><p>如果 npm 安装工具时速度很慢，可以先换网络环境再试。不要随意复制陌生来源的一键换源命令，避免后续下载到不可控的软件包。</p><h3 id="已经装过-node-js-还需要重装吗" tabindex="-1">已经装过 Node.js，还需要重装吗 <a class="header-anchor" href="#已经装过-node-js-还需要重装吗" aria-label="Permalink to &quot;已经装过 Node.js，还需要重装吗&quot;">​</a></h3><p>不一定。只要 <code>node -v</code> 和 <code>npm -v</code> 都能正常显示版本号，并且后续工具可以正常安装，就可以继续使用当前版本。遇到兼容问题时，再考虑升级到 LTS 版本。</p><h3 id="需要安装-nvm、fnm-或-volta-吗" tabindex="-1">需要安装 nvm、fnm 或 Volta 吗 <a class="header-anchor" href="#需要安装-nvm、fnm-或-volta-吗" aria-label="Permalink to &quot;需要安装 nvm、fnm 或 Volta 吗&quot;">​</a></h3><p>普通用户不需要一开始就安装版本管理工具。只有当你需要同时维护多个 Node.js 版本，或者不同项目要求不同 Node.js 版本时，再考虑使用 nvm、fnm 或 Volta。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成 Node.js 环境后，可以继续：</p><ul><li><a href="/guide/register">平台注册</a></li><li><a href="/guide/recharge">账号充值</a></li><li><a href="/guide/api-key">API Key</a></li></ul><p>如果你使用的是 Codex App，并且没有用 npm 安装 Codex CLI，可以直接跳过本页。</p>`,60)])])}const g=s(n,[["render",l]]);export{k as __pageData,g as default};
